/**
 * AI 模型服务
 * 不同任务自动选择最合适的模型
 */

export type AIModel = 'doubao-pro' | 'doubao-lite' | 'doubao-mini' | 'deepseek-reasoner'
export type TaskType = 'creative' | 'summary' | 'classification' | 'logic' | 'extraction'

// 模型能力映射
const ModelTaskMapping: Record<TaskType, AIModel> = {
  creative: 'doubao-pro',         // 章节生成、创意续写
  summary: 'doubao-lite',         // 摘要、结构化分析
  classification: 'doubao-mini',  // 极速分类
  logic: 'deepseek-reasoner',     // 逻辑校验、一致性检查
  extraction: 'doubao-lite',      // 事实提取
}

// 模型配置
interface ModelConfig {
  maxTokens: number
  temperature: number
  topP: number
  presencePenalty: number
  frequencyPenalty: number
}

const ModelConfigs: Record<AIModel, ModelConfig> = {
  'doubao-pro': {
    maxTokens: 4096,
    temperature: 0.8,
    topP: 0.9,
    presencePenalty: 0.1,
    frequencyPenalty: 0.1,
  },
  'doubao-lite': {
    maxTokens: 2048,
    temperature: 0.3,
    topP: 0.85,
    presencePenalty: 0.0,
    frequencyPenalty: 0.0,
  },
  'doubao-mini': {
    maxTokens: 1024,
    temperature: 0.1,
    topP: 0.7,
    presencePenalty: 0.0,
    frequencyPenalty: 0.0,
  },
  'deepseek-reasoner': {
    maxTokens: 8192,
    temperature: 0.2,
    topP: 0.95,
    presencePenalty: 0.0,
    frequencyPenalty: 0.0,
  },
}

class AIModelService {
  /**
   * 根据任务类型选择最优模型
   */
  selectModel(taskType: TaskType): AIModel {
    return ModelTaskMapping[taskType] || 'doubao-pro'
  }

  /**
   * 获取模型配置
   */
  getModelConfig(model: AIModel): ModelConfig {
    return ModelConfigs[model] || ModelConfigs['doubao-pro']
  }

  /**
   * 调用 AI 模型 (非流式)
   */
  async call(
    taskType: TaskType,
    prompt: string,
    options?: Partial<ModelConfig> & { systemPrompt?: string }
  ): Promise<{ success: boolean; content?: string; error?: string }> {
    try {
      const model = this.selectModel(taskType)
      const config = { ...this.getModelConfig(model), ...options }

      const result = await window.electronAPI.ai.call(prompt, {
        model,
        ...config,
        systemPrompt: options?.systemPrompt,
      })

      return result
    } catch (error: any) {
      return { success: false, error: error.message }
    }
  }

  /**
   * 流式调用 AI 模型
   */
  async stream(
    taskType: TaskType,
    prompt: string,
    onChunk: (chunk: string, done: boolean) => void,
    onError?: (error: string) => void,
    options?: Partial<ModelConfig> & { systemPrompt?: string }
  ): Promise<void> {
    try {
      const model = this.selectModel(taskType)
      const config = { ...this.getModelConfig(model), ...options }

      // 监听流式输出
      const removeChunkListener = window.electronAPI.ai.onStreamChunk((chunk) => {
        if (chunk.done) {
          onChunk('', true)
          removeChunkListener()
          removeErrorListener()
        } else {
          onChunk(chunk.content, false)
        }
      })

      // 监听错误
      const removeErrorListener = window.electronAPI.ai.onStreamError((error) => {
        if (onError) onError(error)
        removeChunkListener()
        removeErrorListener()
      })

      // 发起流式请求
      await window.electronAPI.ai.stream(prompt, {
        model,
        ...config,
        systemPrompt: options?.systemPrompt,
      })
    } catch (error: any) {
      if (onError) onError(error.message)
    }
  }

  /**
   * 测试模型连接
   */
  async testConnection(model: AIModel): Promise<boolean> {
    try {
      const result = await window.electronAPI.ai.testConnection(model)
      return !!(result.success && result.result)
    } catch {
      return false
    }
  }
}

// 单例导出
const aiModelService = new AIModelService()
export default aiModelService

逐行审查完毕，发现以下问题：

```
[aiModels.ts:94-96] 🟠P1
catch 块中对 error.message 的访问不安全，当 error 不是 Error 实例时会崩溃
代码片段:
    } catch (error: any) {
      return { success: false, error: error.message }
    }
修复建议:
    } catch (error: unknown) {
      const message = error instanceof Error ? error.message : String(error)
      return { success: false, error: message }
    }

[aiModels.ts:115-126] 🟠P1
stream 方法中，try 块内若在 await 之前抛出异常，removeChunkListener 和 removeErrorListener 尚未定义，导致错误监听器无法被清理
代码片段:
    try {
      const model = this.selectModel(taskType)
      const config = { ...this.getModelConfig(model), ...options }

      const removeChunkListener = window.electronAPI.ai.onStreamChunk((chunk) => { ... })
      const removeErrorListener = window.electronAPI.ai.onStreamError((error) => { ... })

      await window.electronAPI.ai.stream(prompt, { ... })  // ← 若这里之前抛异常，监听器泄漏
    } catch (error: any) { ... }
修复建议:
    将监听器注册移到 try 块开头，或使用空函数做 guard：
    let removeChunkListener = () => {}
    let removeErrorListener = () => {}
    try {
      removeChunkListener = window.electronAPI.ai.onStreamChunk((chunk) => { ... })
      removeErrorListener = window.electronAPI.ai.onStreamError((error) => { ... })
      ...
    }

[aiModels.ts:147] 🟠P1
testConnection 假设 result 结构为 { success, result }，但 window.electronAPI.ai.testConnection 可能返回其他结构或 undefined
代码片段:
    const result = await window.electronAPI.ai.testConnection(model)
    return !!(result.success && result.result)
修复建议:
    if (!result || typeof result !== 'object') return false
    return !!(result.success && result.result)

[aiModels.ts:93-96] 🟡P2
call 方法中 config 合并后 systemPrompt 被传了两次：一次通过 ...config（因为 options 包含它），一次显式传递
代码片段:
    const config = { ...this.getModelConfig(model), ...options }
    ...
    systemPrompt: options?.systemPrompt,  // 冗余传递
修复建议:
    调用时直接用 { model, ...config } 即可，不需要单独列出 systemPrompt，或从 config 中解构排除它
```

**总结**：主要是错误处理的防御性不足——假设 `error` 必有 `.message`、假设 `result` 必有指定结构，在生产环境中可能引发次生异常。
